('ONET-BILL_AND_ACCOUNT_COLLECTORS', 'source_onet_bill_and_account_collectors', 'Bill and Account Collectors', 'Bill and Account Collectors is an imported ONET role/occupation concept. It needs TALLENTIN normalization before production routing.', 'role_title', 'Locate and notify customers of delinquent accounts by mail, telephone, or personal visit to solicit payment. Duties include receiving payment and posting amount to customer''s account, preparing statements to credit department if customer fails to respond, initiating repossession proceedings or service disconnection, and keeping records of collection and status of accounts.', ARRAY['Account Receivable Associate','Account Representative','Account Service Representative','Accounts Collector','Accounts Receivable Specialist (AR Specialist)','Bad Credit Collector','Bilingual Collections Specialist','Bill Collector','Billing Representative','Car Repossessor','Chaser','Claims Collector','Collection Agent','Collection Clerk','Collection Representative','Collection Specialist','Collections Agent','Collections Analyst','Collections Associate','Collections Clerk','Collections Coordinator','Collections Officer','Collections Representative','Collections Specialist','Collector','Credit and Collections Analyst','Credit Coordinator','Credit Specialist','Customer Account Specialist','Data Collector','Debt Collector','Dunner','Field Collector','Installment Agent','Installment Loan Collector','Insurance Collector','Medical Collections Specialist','Medical Collector','Patient Access Specialist','Patient Account Representative','Patient Financial Service Representative','Payment Collector','Rent Collector','Repossession Agent','Repossessor','Telephone Collector']::text[], ARRAY['Bill and Account Collectors','Account Receivable Associate','Account Representative','Account Service Representative','Accounts Collector','Accounts Receivable Specialist (AR Specialist)','Bad Credit Collector','Bilingual Collections Specialist','Bill Co